  9→function extractExcerpt(content, maxLen = 120) {
 10→    if (!content) return '';
 11→    try {
 12→        const root = typeof content === 'string' ? JSON.parse(content) : content;
 13→        const texts = [];
 14→        const walk = (node) => {
 15→            if (node.text) texts.push(node.text);
 16→            if (node.children) node.children.forEach(walk);
 17→        };
 18→        walk(root.root || root);
 19→        const full = texts.join(' ').replace(/\s+/g, ' ').trim();
 20→        if (full.length <= maxLen) return full;
 21→        return full.slice(0, maxLen).replace(/\s+\S*$/, '') + '…';
 22→    } catch {
 23→        return '';
 24→    }
 25→}
 26→
 27→const CONFIDENCE_LABELS = {
 28→    high:   "Posts you might like",
 29→    medium: "You might also explore",
 30→    low:    "More from the community",
 31→};
 32→
 33→function RelatedPostCard({ post, index }) {
 34→    const navigate = useNavigate();
 35→
 36→    const handleClick = () => {
 37→        navigate(`/home/post/${post.id}`);
 38→    };
 39→
 40→    const title = post.title || 'Untitled';
 41→    const excerpt = extractExcerpt(post.content);
 42→
 43→    // Map similarity to accent opacity (higher = brighter accent line)
 44→    const accentOpacity = Math.min(1, Math.max(0.3, (post.semantic_similarity - 0.25) / 0.5));
 45→
 46→    return (
 47→        <motion.div
 48→            className="rp-card"
 49→            onClick={handleClick}
 50→            initial={{ opacity: 0, y: 12 }}
 51→            animate={{ opacity: 1, y: 0 }}
 52→            transition={{
 53→                duration: 0.35,
 54→                delay: index * 0.06,
 55→                ease: [0.25, 0.46, 0.45, 0.94],
 56→            }}
 57→        >
 58→            <div
 59→                className="rp-card-accent"
 60→                style={{ opacity: accentOpacity }}
 61→            />
 62→            <div className="rp-card-content">
 63→                <h4 className="rp-card-title">{title}</h4>
 64→                {excerpt && <p className="rp-card-excerpt">{excerpt}</p>}
 65→                <div className="rp-card-meta">
 66→                    <div className="rp-card-author">
 67→                        <div className={`rp-card-avatar-container ${post.user_badge === 'legend' ? 'rp-avatar-ring-legend' : post.user_badge === 'og' ? 'rp-avatar-ring-og' : ''}`}>
 68→                            {post.user_image_url ? (
 69→                                <img
 70→                                    src={post.user_image_url}
 71→                                    alt=""
 72→                                    className="rp-card-avatar"
 73→                                />
 74→                            ) : (
 75→                                <div className="rp-card-avatar rp-card-avatar-placeholder" />
 76→                            )}
 77→                        </div>
 78→                        <span className="rp-card-name">
 79→                            {post.user_name || 'Anonymous'}
 80→                        </span>
 81→                        {post.user_badge && (
 82→                            <VerifiedBadge badge={post.user_badge} size={12} />
 83→                        )}
 84→                    </div>
 85→                    <span className="rp-card-date">
 86→                        {formatPostDate(post.created_at)}
 87→                    </span>
 88→                </div>
 89→            </div>
 90→        </motion.div>
 91→    );
 92→}
