 94→function RelatedPostsSkeleton() {
 95→    return (
 96→        <div className="rp-skeleton-container">
 97→            {[0, 1, 2].map((i) => (
 98→                <div key={i} className="rp-skeleton-card">
 99→                    <div className="rp-skeleton-accent" />
100→                    <div className="rp-skeleton-content">
101→                        <div className="rp-skeleton-title" />
102→                        <div className="rp-skeleton-excerpt" />
103→                        <div className="rp-skeleton-meta">
104→                            <div className="rp-skeleton-avatar" />
105→                            <div className="rp-skeleton-name" />
106→                        </div>
107→                    </div>
108→                </div>
109→            ))}
110→        </div>
111→    );
112→}
113→
114→export default function RelatedPosts({ journalId }) {
115→    const { data, isLoading } = useQuery({
116→        queryKey: ['relatedPosts', journalId],
117→        queryFn: () => getRelatedPosts(journalId),
118→        enabled: !!journalId,
119→        staleTime: 10 * 60 * 1000,
120→        retry: false,
121→    });
122→
123→    if (isLoading) {
124→        return (
125→            <section className="rp-section">
126→                <RelatedPostsSkeleton />
127→            </section>
128→        );
129→    }
130→
131→    // Don't render anything if no confidence or no posts
132→    if (!data || data.confidence === 'none' || !data.posts?.length) {
133→        return null;
134→    }
135→
136→    const label = CONFIDENCE_LABELS[data.confidence];
137→    if (!label) return null;
138→
139→    return (
140→        <section className="rp-section">
141→            <h3 className="rp-heading">
142→                <svg className="rp-heading-icon" viewBox="0 0 16 16" fill="none">
143→                    <path d="M8 1l1.796 4.236L14.5 6.18l-3.25 3.382.588 4.938L8 12.236 4.162 14.5l.588-4.938L1.5 6.18l4.704-.944z"
144→                          stroke="currentColor" strokeWidth="1.2" strokeLinejoin="round" />
145→                    <path d="M8 4.5l.898 2.118L11.25 7.09l-1.625 1.691.294 2.469L8 10.118 5.581 11.25l.294-2.469L4.25 7.09l2.352-.472z"
146→                          fill="currentColor" opacity="0.3" />
147→                </svg>
148→                {label}
149→            </h3>
150→            <div className="rp-grid">
151→                {data.posts.map((post, index) => (
152→                    <RelatedPostCard
153→                        key={post.id}
154→                        post={post}
155→                        index={index}
156→                    />
157→                ))}
158→            </div>
159→        </section>
160→    );
161→}
